class TrieNode:
    def __init__(self):
        self.children = {}
        self.word = None

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.word = word

class Solution:
    def findWords(self, board: list[list[str]], words: list[str]) -> list[str]:
        trie = Trie()
        for word in words:
            trie.insert(word)

        rows, cols = len(board), len(board[0])
        result = set()

        def dfs(r, c, current_node):
            if r < 0 or r >= rows or c < 0 or c >= cols:
                return

            char = board[r][c]
            if char not in current_node.children:
                return

            next_node = current_node.children[char]

            if next_node.word:
                result.add(next_node.word)
                next_node.word = None 

            board[r][c] = '#'

            dfs(r + 1, c, next_node)
            dfs(r - 1, c, next_node)
            dfs(r, c + 1, next_node)
            dfs(r, c - 1, next_node)

            board[r][c] = char

        for r in range(rows):
            for c in range(cols):
                dfs(r, c, trie.root)

        return list(result)
